def test_next_palindrome_returns_not_none_for_typical_input():
    from source import next_palindrome
    result = next_palindrome([1, 4, 3, 4, 1])
    assert result is not None, (
        "next_palindrome([1, 4, 3, 4, 1]) returned None; "
        "expected a list because the ordinary increment branch should return the updated digit list"
    )
    assert isinstance(result, list), (
        "next_palindrome should return a list, got %s" % type(result).__name__
    )
